#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1 = (vUv-.5)*uAspect.xy*tele;
vUv = (vUv-.5)*(1-ds/(GetDist(vUv))) + .5;
//vUv = (vUv-.5)*(1-(1.001*ds/tdist(GetDist(vUv))+dot(compxy,uv1))) + .5;

vec3 noise = fract(8*texture(sampler_noise_lq,vUv+rand_frame.yz));
dist = noise.r; seed = 1;
   if (noise.g > 0.15)
   {  seed = 0;vec3 noiseBiased = noise - 0.3;
      dist = min(MinDist(vUv,2), 111) +  0.008* noiseBiased.x * noise.y ; }

dist = min(dist,GetDist(vUv))- ds*0.7;
uv2 = multiply(vec3(uv1*tdist(dist),tdist(dist)-.0)/myzoom,RotMat)+CamPos;
uv2 = (fract(uv2/4+.5)-.5)*2+vec3(1,2,3);
box = mbox (uv2); len = length(box.xyz);

struc = mix(clamp01(1-1.5*dot(box,mod1)/limit),0.5,.0);

if ((len < limit) && (dist > 0.04*(1-vRadius))){
 ret.r = mix(struc,GetPixel(vUv).r,sustain); ret.gb=  PutDist(dist); }
 else {ret = texture(sampler_fc_main,vUv)*sustain  - 1.0/255;}
//ret = 0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += uTexSize.zw/2;
uv0 = vUv;
rdist = GetBlur1(uv0).b;

dz1.x = GetBuf(vUv+pix*vec2(1,0)) - GetBuf(vUv+pix*vec2(-1,0));
dz1.y = GetBuf(vUv+pix*vec2(0,1)) - GetBuf(vUv+pix*vec2(0,-1));
vUv += dz1 * clamp01(1-GetBlur1(vUv).r*0.8)*0.2;
rdist = GetBlur1(vUv).b;

col1 = texture(sampler_noise_hq,rdist*0.05+uTime*0.02);
col1 = mix(col1,roam_sin,0.5);
col2 = texture(sampler_noise_hq,rdist*0.06+uTime*0.027);
col2 = mix(col2,roam_sin,0.5);
col2 = col1.bgr;

uv4 = vUv-0.5-GetBlur1(vUv).r*0.4;
uva = uv4-pos1;
uvb = uv4-pos2;
cross1 = abs(sin(M_PI*(aTan2(uva.x,uva.y)+4*q20)))+rdist*0.5+0.1;
flash1 = 1/dot(uva,uva)/cross1*(1-rdist);
flash2 = 1/dot(uvb,uvb)*(rdist+0.5);

float r0 = rdist;
ret = clamp01(1-2*r0) * (flash1*col1*q3 + flash2*(1-col1)*q19+0.1);
ret += clamp01(2*r0)  * (flash1*col2*q3 + flash2*(1-col2)*q19);

ret += GetBuf(vUv)*0.05;
//ret *= 1-(rand_preset.y-0.5)*GetBuf(vUv);

ret = 1-exp(-ret);


  fragColor = ret;
}
